/* eslint-disable @typescript-eslint/no-duplicate-type-constituents */
/// <reference no-default-lib="true"/>

/**
 * The base interface of an array iterable object in CoHTML (Ore UI).
 *
 * @template T The value type.
 * @template Parent The parent object.
 */
interface CoherentArrayIterableBase<T, Parent = any> {
    /**
     * Returns the number of elements in the iterable.
     */
    readonly length: number;
    /**
     * Returns an iterable of key, value pairs for every entry in the iterable.
     */
    entries(): ArrayIterator<[key: number, value: T]>;
    /**
     * Returns an iterable of keys in the iterable
     */
    keys(): ArrayIterator<number>;
    /**
     * Returns an iterable of values in the iterable
     */
    values(): ArrayIterator<T>;
    /**
     * Performs the specified action for each item in the iterable.
     *
     * @param callbackfn A function that accepts up to three arguments. forEach calls the callbackfn function one time for each item in the iterable.
     */
    forEach(callbackfn: (this: undefined, value: T, key: number, parent: Parent) => void): void;
    /**
     * Performs the specified action for each item in the iterable.
     *
     * @template ThisArg The type of the this keyword in the callbackfn function.
     * @param callbackfn A function that accepts up to three arguments. forEach calls the callbackfn function one time for each item in the iterable.
     * @param thisArg An object to which the this keyword can refer in the callbackfn function. If thisArg is omitted, undefined is used as the this value.
     */
    forEach<ThisArg>(callbackfn: (this: ThisArg, value: T, key: number, parent: Parent) => void, thisArg: ThisArg): void;
    /**
     * Performs the specified action for each item in the iterable.
     *
     * @param callbackfn A function that accepts up to three arguments. forEach calls the callbackfn function one time for each item in the iterable.
     * @param thisArg An object to which the this keyword can refer in the callbackfn function. If thisArg is omitted, undefined is used as the this value.
     */
    forEach(callbackfn: (value: T, key: number, parent: Parent) => void, thisArg?: any): void;
    [Symbol.iterator](): ArrayIterator<T>;
}

/**
 * This is like {@link CoherentArrayIterableBase} but with support for indexed access and the {@link CoherentArrayIterableIndexableBase.item | item} method.
 *
 * @template T The value type.
 * @template Parent The parent object.
 */
interface CoherentArrayIterableIndexableBase<T, Parent = any> extends CoherentArrayIterableBase<T, Parent> {
    /**
     * Returns the item with the specified index.
     *
     * @param index The index of the item to retrieve.
     * @returns The item at the specified index, or null if the index is out of range.
     */
    item(index: number): T | null;
    [index: number]: T;
}

interface EventListenerOptions {
    /**
     * When set to true, this prevents callback from being invoked when the event's eventPhase attribute value is BUBBLING_PHASE. When false (or not present), callback will not be invoked when event's eventPhase attribute value is CAPTURING_PHASE. Either way, callback will be invoked if event's eventPhase attribute value is AT_TARGET.
     *
     * @default false
     */
    capture?: boolean;
}

interface AddEventListenerOptions extends EventListenerOptions {
    /**
     * When set to true, this indicates that the callback will only be invoked once after which the event listener will be removed.
     *
     * @default false
     */
    once?: boolean;
    /**
     * When set to true, this indicates that the callback will not cancel the event by invoking preventDefault(). This is used to enable performance optimizations described in § 2.8 Observing event listeners.
     *
     * @default false
     */
    passive?: boolean;
}

/**
 * [Coherent Gameface Reference](https://docs.coherent-labs.com/cpp-gameface/api_reference/classes/interface_animation/)
 *
 * [MDN Reference](https://developer.mozilla.org/docs/Web/API/Animation)
 */
interface Animation {
    /**
     * The current time of the animation.
     *
     * [Coherent Gameface Reference](https://docs.coherent-labs.com/cpp-gameface/api_reference/classes/interface_animation/#variable-currenttime)
     *
     * [MDN Reference](https://developer.mozilla.org/docs/Web/API/Animation/currentTime)
     */
    currentTime: CSSNumberish | null;
    /**
     * The playback rate of the animation.
     *
     * [Coherent Gameface Reference](https://docs.coherent-labs.com/cpp-gameface/api_reference/classes/interface_animation/#variable-playbackrate)
     *
     * [MDN Reference](https://developer.mozilla.org/docs/Web/API/Animation/playbackRate)
     */
    playbackRate: number;
    /**
     * [Coherent Gameface Reference](https://docs.coherent-labs.com/cpp-gameface/api_reference/classes/interface_animation/#variable-finish)
     *
     * [MDN Reference](https://developer.mozilla.org/docs/Web/API/Animation/finish_event)
     */
    onfinish: ((this: Animation, event: Event) => any) | null;
    /**
     * [Coherent Gameface Reference](https://docs.coherent-labs.com/cpp-gameface/api_reference/classes/interface_animation/#function-cancel)
     *
     * [MDN Reference](https://developer.mozilla.org/docs/Web/API/Animation/cancel)
     */
    cancel(): void;
    /**
     * [Coherent Gameface Reference](https://docs.coherent-labs.com/cpp-gameface/api_reference/classes/interface_animation/#function-commitstyles)
     *
     * [MDN Reference](https://developer.mozilla.org/docs/Web/API/Animation/commitStyles)
     */
    commitStyles(): void;
    /**
     * [Coherent Gameface Reference](https://docs.coherent-labs.com/cpp-gameface/api_reference/classes/interface_animation/#function-finish)
     *
     * [MDN Reference](https://developer.mozilla.org/docs/Web/API/Animation/finish)
     */
    finish(): void;
    /**
     * Pauses the animation if running, does nothing if finished/paused.
     *
     * [Coherent Gameface Reference](https://docs.coherent-labs.com/cpp-gameface/api_reference/classes/interface_animation/#function-pause)
     *
     * [MDN Reference](https://developer.mozilla.org/docs/Web/API/Animation/pause)
     */
    pause(): void;
    /**
     * [Coherent Gameface Reference](https://docs.coherent-labs.com/cpp-gameface/api_reference/classes/interface_animation/#function-persist)
     *
     * [MDN Reference](https://developer.mozilla.org/docs/Web/API/Animation/persist)
     */
    persist(): void;
    /**
     * Starts playing the animation if paused, does nothing if already running.
     *
     * [Coherent Gameface Reference](https://docs.coherent-labs.com/cpp-gameface/api_reference/classes/interface_animation/#function-play)
     *
     * [MDN Reference](https://developer.mozilla.org/docs/Web/API/Animation/play)
     */
    play(): void;
    /**
     * Plays an animation from the selected time to the pause time. When the pauseTime is reached, the animation is automatically paused and the callback is invoked.
     *
     * @param startTimeMs The time in milliseconds counted from the beginning of the animation to seek to.
     * @param pauseTimeMs The time in milliseconds counted from the beginning of the animation to pause at.
     * @param callback The callback to invoke when the animation is paused.
     *
     * @description
     * `playFromTo` is a specific Gameface-only API that extends the Web Animations to give easier control to UI developers.
     *
     * When called, the animation will seek to startTimeMs and pause when it reaches pauseTimeMs.
     *
     * Both units are in milliseconds counted from the beginning of the animation.
     *
     * Calling play, pause or any other control API while the animation hasn’t reached its pauseTimeMs will cancel the scheduled pause.
     *
     * [Coherent Gameface Reference](https://docs.coherent-labs.com/cpp-gameface/api_reference/classes/interface_animation/)
     *
     * [Coherent Gameface Web Animations API Reference](https://docs.coherent-labs.com/unity-gameface/content_development/animations/#WebAnims)
     */
    playFromTo(
        startTimeMs: number,
        pauseTimeMs: number,
        /**
         * @todo Figure out this `this` type of this callback.
         */
        callback?: Function
    ): void;
    /**
     * Reverses the animations playbackRate and plays it.
     *
     * [Coherent Gameface Reference](https://docs.coherent-labs.com/cpp-gameface/api_reference/classes/interface_animation/#function-reverse)
     *
     * [MDN Reference](https://developer.mozilla.org/docs/Web/API/Animation/reverse)
     */
    reverse(): void;
}

declare var Animation: {
    prototype: Animation;
    /**
     * @throws {TypeError} Throws an `Illegal constructor` error as this is only constructable by the engine itself.
     */
    new (): Animation;
};

