/**
 * Provides the ability to watch for changes being made to the DOM tree. It is designed as a replacement for the older Mutation Events feature which was part of the DOM3 Events specification.
 *
 * [Coherent Gameface Reference](https://docs.coherent-labs.com/cpp-gameface/api_reference/classes/interface_mutation_observer/)
 *
 * [MDN Reference](https://developer.mozilla.org/docs/Web/API/MutationObserver)
 */
interface MutationObserver {
    // mutationObserver(callback: Function): MutationObserver;
    /**
     * Stops observer from observing any mutations. Until the observe() method is used again, observer's callback will not be invoked.
     *
     * [Coherent Gameface Reference](https://docs.coherent-labs.com/cpp-gameface/api_reference/classes/interface_mutation_observer/#function-disconnect)
     *
     * [MDN Reference](https://developer.mozilla.org/docs/Web/API/MutationObserver/disconnect)
     */
    disconnect(): void;
    /**
     * Instructs the user agent to observe a given target (a node) and report any mutations based on the criteria given by options (an object).
     *
     * The options argument allows for setting mutation observation options via object members.
     *
     * [Coherent Gameface Reference](https://docs.coherent-labs.com/cpp-gameface/api_reference/classes/interface_mutation_observer/#function-observe)
     *
     * [MDN Reference](https://developer.mozilla.org/docs/Web/API/MutationObserver/observe)
     */
    observe(target: Node, options?: Partial<MutationObserverInit>): void;
    /**
     * Empties the record queue and returns what was in there.
     *
     * [Coherent Gameface Reference](https://docs.coherent-labs.com/cpp-gameface/api_reference/classes/interface_mutation_observer/#function-takerecords)
     *
     * [MDN Reference](https://developer.mozilla.org/docs/Web/API/MutationObserver/takeRecords)
     */
    takeRecords(): MutationRecord[];
}

declare var MutationObserver: {
    prototype: MutationObserver;
    new (callback: MutationCallback): MutationObserver;
};

/**
 * [Coherent Gameface Reference](https://docs.coherent-labs.com/cpp-gameface/api_reference/modules/group___d_o_m___a_p_i/#variable-mutationcallback)
 */
interface MutationCallback {
    // eslint-disable-next-line @typescript-eslint/prefer-function-type
    (mutations: MutationRecord[], observer: MutationObserver): void;
}

/**
 * [Coherent Gameface Reference](https://docs.coherent-labs.com/cpp-gameface/api_reference/classes/interface_mutation_observer_init/)
 */
interface MutationObserverInit {
    /**
     * Set to true if mutations to target's children are to be observed.
     *
     * [Coherent Gameface Reference](https://docs.coherent-labs.com/cpp-gameface/api_reference/classes/interface_mutation_observer_init/#variable-childlist)
     */
    childList: boolean;
    /**
     * Set to true if mutations to target's attributes are to be observed. Can be omitted if attributeOldValue or attributeFilter is specified.
     *
     * [Coherent Gameface Reference](https://docs.coherent-labs.com/cpp-gameface/api_reference/classes/interface_mutation_observer_init/#variable-attributes)
     */
    attributes: boolean;
    /**
     * Set to true if mutations to target's data are to be observed. Can be omitted if characterDataOldValue is specified.
     *
     * [Coherent Gameface Reference](https://docs.coherent-labs.com/cpp-gameface/api_reference/classes/interface_mutation_observer_init/#variable-characterdata)
     */
    characterData: boolean;
    /**
     * Set to true if mutations to not just target, but also target's descendants are to be observed.
     *
     * [Coherent Gameface Reference](https://docs.coherent-labs.com/cpp-gameface/api_reference/classes/interface_mutation_observer_init/#variable-subtree)
     */
    subtree: boolean;
    /**
     * Set to true if attributes is true or omitted and target's attribute value before the mutation needs to be recorded.
     *
     * [Coherent Gameface Reference](https://docs.coherent-labs.com/cpp-gameface/api_reference/classes/interface_mutation_observer_init/#variable-attributeoldvalue)
     */
    attributeOldValue: boolean;
    /**
     * Set to true if characterData is set to true or omitted and target's data before the mutation needs to be recorded.
     *
     * [Coherent Gameface Reference](https://docs.coherent-labs.com/cpp-gameface/api_reference/classes/interface_mutation_observer_init/#variable-characterdataoldvalue)
     */
    characterDataOldValue: boolean;
    /**
     * Set to a list of attribute local names (without namespace) if not all attribute mutations need to be observed and attributes is true or omitted.
     *
     * [Coherent Gameface Reference](https://docs.coherent-labs.com/cpp-gameface/api_reference/classes/interface_mutation_observer_init/#variable-attributefilter)
     */
    attributeFilter: string[];
}

declare var MutationObserverInit: {
    prototype: MutationObserverInit;
    /**
     * @throws {TypeError} Throws an `Illegal constructor` error as this is only constructable by the engine itself.
     */
    new (): MutationObserverInit;
};

/**
 * A MutationRecord represents an individual DOM mutation. It is the object that is passed to MutationObserver's callback.
 *
 * [Coherent Gameface Reference](https://docs.coherent-labs.com/cpp-gameface/api_reference/classes/interface_mutation_record/)
 *
 * [MDN Reference](https://developer.mozilla.org/docs/Web/API/MutationRecord)
 */
interface MutationRecord {
    /**
     * Returns "attributes" if it was an attribute mutation. "characterData" if it was a mutation to a CharacterData node. And "childList" if it was a mutation to the tree of nodes.
     *
     * [Coherent Gameface Reference](https://docs.coherent-labs.com/cpp-gameface/api_reference/classes/interface_mutation_record/#variable-type)
     *
     * [MDN Reference](https://developer.mozilla.org/docs/Web/API/MutationRecord/type)
     */
    readonly type: MutationRecordType;
    /**
     * Returns the node the mutation affected, depending on the type. For "attributes", it is the element whose attribute changed. For "characterData", it is the CharacterData node. For "childList", it is the node whose children changed.
     *
     * [Coherent Gameface Reference](https://docs.coherent-labs.com/cpp-gameface/api_reference/classes/interface_mutation_record/#variable-target)
     *
     * [MDN Reference](https://developer.mozilla.org/docs/Web/API/MutationRecord/target)
     */
    readonly target: Node;
    /**
     * Return the nodes added and removed respectively.
     *
     * [Coherent Gameface Reference](https://docs.coherent-labs.com/cpp-gameface/api_reference/classes/interface_mutation_record/#variable-addednodes)
     *
     * [MDN Reference](https://developer.mozilla.org/docs/Web/API/MutationRecord/addedNodes)
     */
    readonly addedNodes: NodeList;
    /**
     * Return the nodes added and removed respectively.
     *
     * [Coherent Gameface Reference](https://docs.coherent-labs.com/cpp-gameface/api_reference/classes/interface_mutation_record/#variable-removednodes)
     *
     * [MDN Reference](https://developer.mozilla.org/docs/Web/API/MutationRecord/removedNodes)
     */
    readonly removedNodes: NodeList;
    /**
     * Return the previous and next sibling respectively of the added or removed nodes, and null otherwise.
     *
     * [Coherent Gameface Reference](https://docs.coherent-labs.com/cpp-gameface/api_reference/classes/interface_mutation_record/#variable-previousSibling)
     *
     * [MDN Reference](https://developer.mozilla.org/docs/Web/API/MutationRecord/previousSibling)
     */
    readonly previousSibling: Node | null;
    /**
     * Return the previous and next sibling respectively of the added or removed nodes, and null otherwise.
     *
     * [Coherent Gameface Reference](https://docs.coherent-labs.com/cpp-gameface/api_reference/classes/interface_mutation_record/#variable-nextSibling)
     *
     * [MDN Reference](https://developer.mozilla.org/docs/Web/API/MutationRecord/nextSibling)
     */
    readonly nextSibling: Node | null;
    /**
     * Returns the local name of the changed attribute, and null otherwise.
     *
     * [Coherent Gameface Reference](https://docs.coherent-labs.com/cpp-gameface/api_reference/classes/interface_mutation_record/#variable-attributeName)
     *
     * [MDN Reference](https://developer.mozilla.org/docs/Web/API/MutationRecord/attributeName)
     */
    readonly attributeName: string | null;
    /**
     * Returns the namespace of the changed attribute, and null otherwise.
     *
     * [Coherent Gameface Reference](https://docs.coherent-labs.com/cpp-gameface/api_reference/classes/interface_mutation_record/#variable-attributeNamespace)
     *
     * [MDN Reference](https://developer.mozilla.org/docs/Web/API/MutationRecord/attributeNamespace)
     */
    readonly attributeNamespace: string | null;
    /**
     * The return value depends on type. For "attributes", it is the value of the changed attribute before the change. For "characterData", it is the data of the changed node before the change. For "childList", it is null.
     *
     * [Coherent Gameface Reference](https://docs.coherent-labs.com/cpp-gameface/api_reference/classes/interface_mutation_record/#variable-oldValue)
     *
     * [MDN Reference](https://developer.mozilla.org/docs/Web/API/MutationRecord/oldValue)
     */
    readonly oldValue: string | null;
}

declare var MutationRecord: {
    prototype: MutationRecord;
    /**
     * @throws {TypeError} Throws an `Illegal constructor` error as this is only constructable by the engine itself.
     */
    new (): MutationRecord;
};

