/**
 * Gets a type if it is available on globalThis, and makes a union type with the provided fallback type, if it is not available the fallback type will be used by itself.
 *
 * @template T The type name to look up.
 * @template U The fallback type, will also be used in a union type if the type name exists, unless omitted or set to `never`.
 *
 * @example
 * ```ts
 * // HTMLDivElement | HTMLElement
 * type Div = GlobalTypeUnionIfItExists<"HTMLDivElement", HTMLElement>;
 * // HTMLSpanElement | HTMLUnknownElement
 * type Span = GlobalTypeUnionIfItExists<"HTMLSpanElement", HTMLUnknownElement>;
 * // HTMLBodyElement | Element
 * type Body = GlobalTypeUnionIfItExists<"HTMLBodyElement", Element>;
 * // HTMLElement
 * type NonExistentElementA = GlobalTypeUnionIfItExists<"nonexistentelementa", HTMLElement>;
 * // HTMLUnknownElement
 * type NonExistentElementB = GlobalTypeUnionIfItExists<"nonexistentelementb", HTMLUnknownElement>;
 * // MouseEvent
 * type NonExistentEventA = GlobalTypeUnionIfItExists<"nonexistenteventa", MouseEvent>;
 * // WheelEvent | MouseEvent (If globalThis.WheelEvent exists, otherwise MouseEvent.)
 * type Wheel = GlobalSymbolUnionIfItExists<"WheelEvent", MouseEvent>;
 * ```
 */
type GlobalTypeUnionIfItExists<T extends string, U extends any = never> =
    T extends keyof typeof globalThis ?
        (typeof globalThis)[T] extends { prototype: any } ?
            (typeof globalThis)[T]["prototype"] | U
        :   U
    :   U;
// BUG: This does not actually work for types unless there is a value of the same name with a prototype of that type.

/**
 * If {@link __CoHTML_BrowserCompatMode__ | \_\_CoHTML_BrowserCompatMode\_\_} matches the provided filter and the provided type name exists on globalThis, then the a union of first and second types is used, otherwise the second type is used by itself.
 *
 * @template T The type name to look up.
 * @template U The fallback type, will also be used in a union type if the type name exists, unless omitted or set to `never`.
 * @template F The filter type, used to determine when to try to use the browser compatible type. Defaults to `"any_compat"`.
 */
type BrowserCompatUnionIE<
    T extends keyof typeof globalThis | (Omit<string, keyof typeof globalThis> & string),
    U extends any = never,
    F extends __CoHTML_BrowserCompatModeOptionFilterType__ = "any_compat",
> = __CoHTML_BrowserCompatMode__ extends __CoHTML_BrowserCompatModeOptionFilter__<F> ? GlobalTypeUnionIfItExists<T, U> : U;

/**
 * If {@link __CoHTML_BrowserCompatMode__ | \_\_CoHTML_BrowserCompatMode\_\_} matches the provided filter, then the first is used, otherwise the second type is used.
 *
 * @template T The browser compatible type.
 * @template U The CoHTML type.
 * @template F The filter type, used to determine when to try to use the browser compatible type. Defaults to `"any_compat"`.
 */
type BrowserCompatSwitch<T extends any, U extends any, F extends __CoHTML_BrowserCompatModeOptionFilterType__ = "any_compat"> =
    __CoHTML_BrowserCompatMode__ extends __CoHTML_BrowserCompatModeOptionFilter__<F> ? T : U;

/**
 * If {@link __CoHTML_BrowserCompatMode__ | \_\_CoHTML_BrowserCompatMode\_\_} matches the provided filter, then the a union of first and second types is used, otherwise the second type is used by itself.
 *
 * @template T The browser compatible type.
 * @template U The CoHTML type.
 * @template F The filter type, used to determine when to try to use the browser compatible type. Defaults to `"any_compat"`.
 */
type BrowserCompatUnion<T extends any, U extends any, F extends __CoHTML_BrowserCompatModeOptionFilterType__ = "any_compat"> =
    __CoHTML_BrowserCompatMode__ extends __CoHTML_BrowserCompatModeOptionFilter__<F> ? T | U : U;

/**
 * If {@link __CoHTML_BrowserCompatMode__ | \_\_CoHTML_BrowserCompatMode\_\_} matches the provided filter, then the type will be a partial type, otherwise it will be the original type.
 *
 * @template T The type to make partial.
 * @template F The filter type, used to determine when to try to use the browser compatible type. Defaults to `"any_compat"`.
 */
type BrowserCompatPartial<T extends object, F extends __CoHTML_BrowserCompatModeOptionFilterType__ = "any_compat"> =
    __CoHTML_BrowserCompatMode__ extends __CoHTML_BrowserCompatModeOptionFilter__<F> ? Partial<T> : T;

